const { initialEconomicBurden_USD_per_capita_per_year, longTermEconomicBenefit_USD_per_capita_per_year, totalPotentialCarbonReduction_CO2e_MT_per_year, implementationTimeFactor_Years, policyCostDistributionEquity_0_10, policyBenefitDistributionEquity_0_10, perceivedFairness_Youth_1_10, perceivedFairness_Seniors_1_10, youthSocietalInfluence_0_1, seniorSocietalInfluence_0_1 } = inputs;

// Constants for scaling and weighting
const MAX_BURDEN_IMPACT_ON_ACCEPTANCE = 30; // Max points subtracted for high burden
const MAX_BENEFIT_IMPACT_ON_ACCEPTANCE = 20; // Max points added for high benefit
const BASE_ACCEPTANCE = 50; // Starting point for acceptance (neutral baseline)
const TIME_DECAY_FACTOR = 0.5; // How much longer implementation reduces acceptance score for economic impact
const EQUITY_BONUS_FACTOR = 0.5; // How much equity distribution adds to fairness scores

// --- Step 1: Calculate Adjusted Generational Fairness Scores ---
// Base fairness from input, augmented by policy's cost/benefit distribution equity
let youthFairnessScoreAdjusted = perceivedFairness_Youth_1_10;
youthFairnessScoreAdjusted += (policyCostDistributionEquity_0_10 / 10) * EQUITY_BONUS_FACTOR; // Max 0.5 bonus
youthFairnessScoreAdjusted += (policyBenefitDistributionEquity_0_10 / 10) * EQUITY_BONUS_FACTOR; // Max 0.5 bonus
// Cap the adjusted fairness scores to a realistic range (e.g., 1 to 11, if bonus is 1)
youthFairnessScoreAdjusted = Math.min(10 + EQUITY_BONUS_FACTOR * 2, Math.max(1, youthFairnessScoreAdjusted)); // Max 11 if equity is 10/10

let seniorFairnessScoreAdjusted = perceivedFairness_Seniors_1_10;
seniorFairnessScoreAdjusted += (policyCostDistributionEquity_0_10 / 10) * EQUITY_BONUS_FACTOR;
seniorFairnessScoreAdjusted += (policyBenefitDistributionEquity_0_10 / 10) * EQUITY_BONUS_FACTOR;
seniorFairnessScoreAdjusted = Math.min(10 + EQUITY_BONUS_FACTOR * 2, Math.max(1, seniorFairnessScoreAdjusted));

// --- Step 2: Calculate Economic Impact on Acceptance ---
let economicImpactOnAcceptance = 0;

const BURDEN_THRESHOLD_FOR_IMPACT = 100; // $100/year per capita is a significant burden for max impact
const BENEFIT_THRESHOLD_FOR_IMPACT = 100; // $100/year per capita is a significant benefit for max impact

if (initialEconomicBurden_USD_per_capita_per_year > 0) {
    const burdenPoints = (initialEconomicBurden_USD_per_capita_per_year / BURDEN_THRESHOLD_FOR_IMPACT) * MAX_BURDEN_IMPACT_ON_ACCEPTANCE;
    economicImpactOnAcceptance -= Math.min(MAX_BURDEN_IMPACT_ON_ACCEPTANCE, burdenPoints);
}
if (longTermEconomicBenefit_USD_per_capita_per_year > 0) {
    const benefitPoints = (longTermEconomicBenefit_USD_per_capita_per_year / BENEFIT_THRESHOLD_FOR_IMPACT) * MAX_BENEFIT_IMPACT_ON_ACCEPTANCE;
    economicImpactOnAcceptance += Math.min(MAX_BENEFIT_IMPACT_ON_ACCEPTANCE, benefitPoints);
}

// Factor in implementation timeline: longer timelines might reduce immediate acceptance due to perceived delay in benefits
// Assuming a 'penalty' starts after 5 years
const optimalImplementationYears = 5;
const timePenalty = (implementationTimeFactor_Years > optimalImplementationYears) ? (implementationTimeFactor_Years - optimalImplementationYears) * TIME_DECAY_FACTOR : 0;
economicImpactOnAcceptance -= timePenalty;

// --- Step 3: Calculate Overall Public Acceptance Score ---
// Combine adjusted generational fairness (weighted) and economic impact with a base acceptance.

let weightedYouthAcceptance = youthFairnessScoreAdjusted * youthSocietalInfluence_0_1;
let weightedSeniorAcceptance = seniorFairnessScoreAdjusted * seniorSocietalInfluence_0_1;

let totalSocietalInfluence = youthSocietalInfluence_0_1 + seniorSocietalInfluence_0_1;
totalSocietalInfluence = Math.max(0.01, totalSocietalInfluence); // Avoid division by zero, min influence of 0.01

let averageWeightedFairnessInfluence = (weightedYouthAcceptance + weightedSeniorAcceptance) / totalSocietalInfluence;

// Convert average weighted fairness (roughly 1 to 11) to a 0-35 point contribution
// Scaling: (value - min_val) / (max_val - min_val) * max_contribution
const fairnessContribution = (averageWeightedFairnessInfluence - 1) / (10 + EQUITY_BONUS_FACTOR * 2 - 1) * 35; 

let overallAcceptance = BASE_ACCEPTANCE + economicImpactOnAcceptance + fairnessContribution;

// Cap overall acceptance score between 0 and 100
overallAcceptance = Math.min(100, Math.max(0, overallAcceptance));

// --- Step 4: Calculate Net Annual Carbon Reduction ---
let carbonReduction = totalPotentialCarbonReduction_CO2e_MT_per_year;

// Adjust for implementation timeline: longer timelines mean impact is realized later/slower annually during the ramp-up phase.
// A simple model: reduce potential based on how far past optimal implementation period it is.
const TIME_IMPACT_DECAY_RATE = 0.03; // 3% reduction in realized annual impact for every year past 5 years
if (implementationTimeFactor_Years > optimalImplementationYears) {
    carbonReduction *= Math.max(0, 1 - ((implementationTimeFactor_Years - optimalImplementationYears) * TIME_IMPACT_DECAY_RATE));
}

// Ensure carbon reduction is non-negative
carbonReduction = Math.max(0, carbonReduction);

// --- Step 5: Calculate Generational Equity Index ---
// This measures how balanced the perceived fairness is between youth and seniors.
// A low absolute difference means high equity. Scale it from 0 (max difference) to 10 (no difference).

let fairnessDifference = Math.abs(perceivedFairness_Youth_1_10 - perceivedFairness_Seniors_1_10);
let generationalEquityIndex = Math.max(0, 10 - fairnessDifference); 

return {
    overallPublicAcceptanceScore: parseFloat(overallAcceptance.toFixed(1)),
    netAnnualCarbonReduction_CO2e_MT: parseFloat(carbonReduction.toFixed(2)),
    generationalEquityIndex_0_10: parseFloat(generationalEquityIndex.toFixed(1))
};
